 54→function EmptyViewportMessage({ viewport, message }) {
 55→  return (
 56→    <text
 57→      x={viewport.x + viewport.width / 2}
 58→      y={viewport.y + viewport.height / 2}
 59→      textAnchor="middle"
 60→      dominantBaseline="middle"
 61→      fill="#66768a"
 62→      fontSize={4}
 63→    >
 64→      {message}
 65→    </text>
 66→  );
 67→}
