35→export default function SheetViewportContent({ source }) {
36→  if (!source || source.kind === 'empty') return null;
37→
38→  if (source.kind === 'plan') {
39→    return <PlanViewportContent floor={source.floor} />;
40→  }
41→
42→  if (source.kind === 'section') {
43→    return <SectionSceneLayer scene={source.scene} showTitle={false} />;
44→  }
45→
46→  if (source.kind === 'elevation') {
47→    return (
48→      <ElevationSceneLayer
49→        scene={source.scene}
50→        annotationScene={source.annotationScene}
51→        showTitle={false}
52→      />
53→    );
54→  }
55→
56→  return null;
57→}
