  1→import { useCallback, useEffect, useMemo, useRef } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { MAX_ZOOM, MIN_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  5→import { fitViewportToSheet } from '@/sheets/layout';
  6→import { hitTestViewport, hitTestViewportHandle } from '@/sheets/hitTest';
  7→import { buildSheetScene } from '@/sheets/layout';
  8→import styles from './SvgCanvas.module.css';
  9→import SheetRenderer from './SheetRenderer';
 10→
 11→function screenToSheet(screenX, screenY, viewport, svgRect) {
 12→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 13→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 14→  return { x, y };
 15→}
 16→
 17→export default function SheetCanvas() {
 18→  const svgRef = useRef(null);
 19→  const dragState = useRef(null);
 20→  const isPanning = useRef(false);
 21→  const lastPanPos = useRef({ x: 0, y: 0 });
 22→
 23→  const { project, dispatch } = useProject();
 24→  const {
 25→    activeSheetId,
 26→    selectedId,
 27→    selectedType,
 28→    viewport,
 29→    dispatch: editorDispatch,
 30→  } = useEditor();
 31→
 32→  const sheet = (project.sheets || []).find((entry) => entry.id === activeSheetId) || null;
 33→  const scene = useMemo(() => buildSheetScene(project, sheet), [project, sheet]);
 34→
 35→  const getSheetPos = useCallback((event) => {
 36→    const rect = svgRef.current.getBoundingClientRect();
 37→    return screenToSheet(event.clientX, event.clientY, viewport, rect);
 38→  }, [viewport]);
 39→
 40→  const updateViewport = useCallback((viewportId, updates) => {
 41→    if (!sheet) return;
 42→    const current = (sheet.viewports || []).find((entry) => entry.id === viewportId);
 43→    if (!current) return;
 44→    const nextViewport = fitViewportToSheet({ ...current, ...updates }, sheet);
 45→    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
 46→  }, [dispatch, sheet]);
 47→
 48→  const handleMouseDown = useCallback((event) => {
 49→    if (event.button === 1 || (event.button === 0 && event.shiftKey)) {
 50→      isPanning.current = true;
 51→      lastPanPos.current = { x: event.clientX, y: event.clientY };
 52→      event.preventDefault();
 53→      return;
 54→    }
 55→
 56→    if (!sheet || !scene) return;
 57→
 58→    const point = getSheetPos(event);
 59→    const handleHit = selectedType === 'sheetViewport' && selectedId
 60→      ? hitTestViewportHandle(point, scene.viewports.filter((entry) => entry.id === selectedId), 6 / viewport.zoom)
 61→      : null;
 62→
 63→    if (handleHit) {
 64→      dragState.current = {
 65→        mode: 'resize',
 66→        viewportId: handleHit.viewportId,
 67→        handle: handleHit.handle,
 68→        origin: point,
 69→        initialViewport: sheet.viewports.find((entry) => entry.id === handleHit.viewportId),
 70→      };
 71→      return;
 72→    }
 73→
 74→    const viewportHit = hitTestViewport(point, scene.viewports);
 75→    if (viewportHit) {
 76→      editorDispatch({ type: 'SELECT_OBJECT', id: viewportHit.id, objectType: 'sheetViewport' });
 77→      dragState.current = {
 78→        mode: 'move',
 79→        viewportId: viewportHit.id,
 80→        origin: point,
 81→        initialViewport: sheet.viewports.find((entry) => entry.id === viewportHit.id),
 82→      };
 83→      return;
 84→    }
 85→
 86→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
 87→    dragState.current = null;
 88→  }, [editorDispatch, getSheetPos, scene, selectedId, selectedType, sheet, viewport.zoom]);
 89→
 90→  const handleMouseMove = useCallback((event) => {
 91→    if (isPanning.current) {
 92→      const dx = event.clientX - lastPanPos.current.x;
 93→      const dy = event.clientY - lastPanPos.current.y;
 94→      editorDispatch({ type: 'PAN', dx, dy });
 95→      lastPanPos.current = { x: event.clientX, y: event.clientY };
 96→      return;
 97→    }
 98→
 99→    if (!dragState.current || !sheet) return;
100→
101→    const point = getSheetPos(event);
102→    const { initialViewport, origin, mode, handle, viewportId } = dragState.current;
103→    const dx = point.x - origin.x;
104→    const dy = point.y - origin.y;
105→
106→    if (mode === 'move') {
107→      updateViewport(viewportId, {
108→        x: initialViewport.x + dx,
109→        y: initialViewport.y + dy,
110→      });
111→      return;
112→    }
113→
114→    const next = {
115→      x: initialViewport.x,
116→      y: initialViewport.y,
117→      width: initialViewport.width,
118→      height: initialViewport.height,
119→    };
120→
121→    if (handle.includes('n')) {
122→      next.y = initialViewport.y + dy;
123→      next.height = initialViewport.height - dy;
124→    }
125→    if (handle.includes('s')) {
126→      next.height = initialViewport.height + dy;
127→    }
128→    if (handle.includes('w')) {
129→      next.x = initialViewport.x + dx;
130→      next.width = initialViewport.width - dx;
131→    }
132→    if (handle.includes('e')) {
133→      next.width = initialViewport.width + dx;
134→    }
135→
136→    updateViewport(viewportId, next);
137→  }, [editorDispatch, getSheetPos, sheet, updateViewport]);
138→
139→  const handleMouseUp = useCallback(() => {
140→    isPanning.current = false;
141→    dragState.current = null;
142→  }, []);
143→
144→  const handleWheel = useCallback((event) => {
145→    event.preventDefault();
146→    const rect = svgRef.current.getBoundingClientRect();
147→    const mouseX = event.clientX - rect.left;
148→    const mouseY = event.clientY - rect.top;
149→    const direction = event.deltaY < 0 ? 1 : -1;
150→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
151→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
152→    const panX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
153→    const panY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
154→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX, panY });
155→  }, [editorDispatch, viewport]);
156→
157→  useEffect(() => {
158→    const svg = svgRef.current;
159→    if (!svg) return undefined;
160→    const prevent = (event) => event.preventDefault();
161→    svg.addEventListener('contextmenu', prevent);
162→    svg.addEventListener('wheel', handleWheel, { passive: false });
163→    return () => {
164→      svg.removeEventListener('contextmenu', prevent);
165→      svg.removeEventListener('wheel', handleWheel);
166→    };
167→  }, [handleWheel]);
168→
169→  return (
170→    <div className={styles.canvasContainer}>
171→      <svg
172→        ref={svgRef}
173→        className={styles.svg}
174→        style={{ cursor: dragState.current ? 'grabbing' : 'default' }}
175→        onMouseDown={handleMouseDown}
176→        onMouseMove={handleMouseMove}
177→        onMouseUp={handleMouseUp}
178→      >
179→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
180→          {sheet ? (
181→            <SheetRenderer
182→              project={project}
183→              sheet={sheet}
184→              selectedId={selectedId}
185→              selectedType={selectedType}
186→            />
187→          ) : (
188→            <g className="sheet-empty">
189→              <rect x={0} y={0} width={420} height={297} fill="#f6f7f9" stroke="#d0d6de" strokeDasharray="2 2" />
190→              <text x={210} y={148} textAnchor="middle" dominantBaseline="middle" fill="#66768a" fontSize={12}>
191→                Create a sheet from the sidebar or properties panel.
192→              </text>
193→            </g>
194→          )}
195→        </g>
196→      </svg>
197→      {sheet && scene && (
198→        <svg
199→          data-sheet-export-root="true"
200→          width={scene.paper.width}
201→          height={scene.paper.height}
202→          viewBox={`0 0 ${scene.paper.width} ${scene.paper.height}`}
203→          style={{
204→            position: 'absolute',
205→            width: 0,
206→            height: 0,
207→            overflow: 'hidden',
208→            pointerEvents: 'none',
209→            opacity: 0,
210→          }}
211→          aria-hidden="true"
212→        >
213→          <SheetRenderer
214→            project={project}
215→            sheet={sheet}
216→            selectedId={null}
217→            selectedType={null}
218→          />
219→        </svg>
220→      )}
221→      <div className={styles.statusBar}>
222→        <span>Workspace: sheet</span>
223→        <span>Sheet: {sheet?.title || 'None'}</span>
224→        <span>Zoom: {Math.round(viewport.zoom * 100)}%</span>
225→      </div>
226→    </div>
227→  );
228→}
